function isServicesMobile(){return window.innerWidth<=470}function setShowMoreEvent(){const e=document.querySelector(".services-detail-description__show-more");e&&e.addEventListener("click",function(){document.querySelector(".services-detail-description__wrapper").style.height=document.querySelector(".services-detail-description__text").clientHeight+15+"px",this.style.display="none"})}function collapseTextOnResize(){const e=document.querySelector(".services-detail-description__wrapper");if(e){let t=e.querySelector(".services-detail-description__text"),i=document.querySelector(".services-detail-description__show-more");isServicesMobile()?(e.clientHeight>200&&(e.style.height="200px"),e.clientHeight<t.clientHeight?i.style.display="block":i.style.display="none"):(e.style.height="auto",i.style.display="none")}}function setItemsWrappersHeights(){let e=document.querySelectorAll(".service-detail-item-wrapper");if(e)for(let t=0;t<e.length;t++)e[t].style.height=e[t].querySelector(".service-detail-item").offsetHeight+"px",e[t].querySelector(".service-detail-item").style.zIndex=e.length+2-t}function showOnHover(){let e=document.querySelectorAll(".service-detail-item");if(e)for(let t=0;t<e.length;t++)e[t].addEventListener("mouseenter",function(){const i=e[t].querySelector(".service-detail-item__content-hidden-wrapper");i&&(i.style.height=i.querySelector(".service-detail-item__content-hidden").clientHeight+"px")}),e[t].addEventListener("mouseleave",function(){e[t].querySelector(".service-detail-item__content-hidden-wrapper")&&(e[t].querySelector(".service-detail-item__content-hidden-wrapper").style.height="0px")})}window.addEventListener("DOMContentLoaded",function(){showOnHover(),setItemsWrappersHeights(),setShowMoreEvent(),collapseTextOnResize()}),window.addEventListener("load",setItemsWrappersHeights),window.addEventListener("resize",function(){setItemsWrappersHeights(),collapseTextOnResize()});